+        asset_id: "asset-4".to_string(),
+        expected: "ccc".to_string(),
+        actual: "ddd".to_string(),
+    };
+    let s = err.to_string();
+    assert!(s.contains("expected output hash mismatch"));
+    assert!(s.contains("ccc"));
+    assert!(s.contains("ddd"));
+}
